// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title CreditScore
 * @notice Stores and computes on-chain credit scores based on repayment behaviour
 */
contract CreditScore {
    struct UserRecord {
        uint256 totalLoans;
        uint256 completedLoans;
        uint256 onTimeRepayments;
        uint256 defaults;
        uint256 totalBorrowed;
        uint256 score;
    }

    mapping(address => UserRecord) public records;

    uint256 public constant BASE_SCORE = 500;
    uint256 public constant COMPLETED_WEIGHT = 20;
    uint256 public constant ON_TIME_MULTIPLIER = 2;
    uint256 public constant DEFAULT_PENALTY = 50;

    address public loanFactory;
    mapping(address => bool) public approvedLoans;

    modifier onlyLoanFactoryOrLoan() {
        require(
            msg.sender == loanFactory || approvedLoans[msg.sender],
            "Only LoanFactory or Loan"
        );
        _;
    }

    modifier onlyLoanFactory() {
        require(msg.sender == loanFactory, "Only LoanFactory");
        _;
    }

    function addApprovedLoan(address loan) external onlyLoanFactory {
        approvedLoans[loan] = true;
    }

    constructor(address _loanFactory) {
        loanFactory = _loanFactory;
    }

    function getScore(address user) external view returns (uint256) {
        return records[user].score == 0 ? BASE_SCORE : records[user].score;
    }

    function recordRepayment(
        address user,
        uint256 principal,
        bool onTime
    ) external onlyLoanFactoryOrLoan {
        UserRecord storage r = records[user];
        r.completedLoans += 1;
        if (onTime) r.onTimeRepayments += 1;
        r.totalBorrowed += principal;
        _updateScore(user);
    }

    function recordDefault(address user, uint256 principal) external onlyLoanFactoryOrLoan {
        UserRecord storage r = records[user];
        r.defaults += 1;
        r.totalBorrowed += principal;
        _updateScore(user);
    }

    function recordLoanRequest(address user, uint256 principal) external onlyLoanFactory {
        records[user].totalLoans += 1;
    }

    function _updateScore(address user) internal {
        UserRecord storage r = records[user];
        uint256 onTimeRate = r.completedLoans > 0
            ? (r.onTimeRepayments * 100) / r.completedLoans
            : 100;
        uint256 score = BASE_SCORE;
        score += r.completedLoans * COMPLETED_WEIGHT;
        score += (onTimeRate * ON_TIME_MULTIPLIER) / 10;
        if (r.defaults > 0) {
            score -= r.defaults * DEFAULT_PENALTY;
        }
        r.score = score > 0 ? score : 0;
    }

    /**
     * @notice Calculates the interest rate in BPS based on user credit score
     * @param user The address of the borrower
     * @return interestRateBps The calculated interest rate in basis points
     */
    function calculateInterestRate(address user) external view returns (uint256 interestRateBps) {
        uint256 score = this.getScore(user);
        
        if (score >= 800) {
            return 400; // 4%
        } else if (score >= 600) {
            return 800; // 8%
        } else if (score >= 400) {
            return 1200; // 12%
        } else {
            return 2000; // 20%
        }
    }
}

contracts/LendingPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./Loan.sol";
import "./CreditScore.sol";

/**
 * @title LendingPool
 * @notice A professional liquidity pool vault where lenders deposit CTC to earn interest
 * and borrowers draw instant liquidity.
 */
contract LendingPool {
    string public constant name = "CredTrust Liquidity Vault";
    
    uint256 public totalShares;
    mapping(address => uint256) public shares;
    
    address public factory;
    ICreditScore public creditScore;

    event Deposited(address indexed user, uint256 amount, uint256 sharesMinted);
    event Withdrawn(address indexed user, uint256 amount, uint256 sharesBurned);
    event LoanFunded(address indexed loan, uint256 amount);
    event InterestEarned(uint256 amount);

    modifier onlyFactory() {
        require(msg.sender == factory, "Only factory can fund loans");
        _;
    }

    constructor(address _factory, address _creditScore) {
        factory = _factory;
        creditScore = ICreditScore(_creditScore);
    }

    /**
     * @notice Deposit CTC into the pool to earn interest
     */
    function deposit() external payable {
        require(msg.value > 0, "Deposit must be > 0");
        
        uint256 sharesToMint;
        if (totalShares == 0) {
            sharesToMint = msg.value;
        } else {
            // shares = deposit * (totalShares / totalBalanceBefore)
            uint256 poolBalanceBefore = address(this).balance - msg.value;
            sharesToMint = (msg.value * totalShares) / poolBalanceBefore;
        }

        shares[msg.sender] += sharesToMint;
        totalShares += sharesToMint;

        emit Deposited(msg.sender, msg.value, sharesToMint);
    }

    /**
     * @notice Withdraw CTC and earned interest from the pool
     * @param sharesToBurn Number of shares to convert back to CTC
     */
    function withdraw(uint256 sharesToBurn) external {
        require(sharesToBurn > 0 && shares[msg.sender] >= sharesToBurn, "Invalid shares");

        // amount = sharesToBurn * (totalBalance / totalShares)
        uint256 amountToWithdraw = (sharesToBurn * address(this).balance) / totalShares;

        shares[msg.sender] -= sharesToBurn;
        totalShares -= sharesToBurn;

        (bool sent, ) = msg.sender.call{value: amountToWithdraw}("");
        require(sent, "Transfer failed");

        emit Withdrawn(msg.sender, amountToWithdraw, sharesToBurn);
    }

    /**
     * @notice Funds an approved loan request instantly from the pool
     * @param loanAddress The address of the Loan contract to fund
     */
    function fundLoan(address payable loanAddress) external onlyFactory {
        Loan loan = Loan(loanAddress);
        require(loan.status() == Loan.Status.Requested, "Loan not requestable");
        
        uint256 amount = loan.principal();
        require(address(this).balance >= amount, "Insufficient pool liquidity");

        // Call the fund function on the loan contract
        loan.fund{value: amount}();
        
        emit LoanFunded(loanAddress, amount);
    }

    /**
     * @notice Returns the current value of a user's shares in CTC
     */
    function getBalanceOf(address user) external view returns (uint256) {
        if (totalShares == 0) return 0;
        return (shares[user] * address(this).balance) / totalShares;
    }

    /**
     * @notice Fallback to receive repayments from Loan contracts
     */
    receive() external payable {
        // Any CTC sent here (from Loan repayments) naturally increases the share value
        emit InterestEarned(msg.value);
    }
}

contracts/Loan.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface ICreditScore {
    function recordRepayment(address user, uint256 principal, bool onTime) external;
    function recordDefault(address user, uint256 principal) external;
}

/**
 * @title Loan
 * @notice Single loan agreement: Requested → Funded → Active → Repaid / Defaulted
 */
contract Loan {
    enum Status {
        Requested,
        Funded,
        Active,
        Repaid,
        Defaulted
    }

    address public borrower;
    uint256 public principal;
    uint256 public interestRateBps; // basis points, e.g. 500 = 5%
    uint256 public durationDays;
    uint256 public fundedAt;
    uint256 public repaymentDeadline;
    uint256 public totalFunded;

    address[] public lenders;
    mapping(address => uint256) public contributions;

    Status public status;
    address public factory;
    ICreditScore public creditScore;

    event LoanFunded(address indexed lender, uint256 amount);
    event LoanPartiallyFunded(address indexed lender, uint256 amount, uint256 remaining);
    event LoanRepaid(address indexed borrower, uint256 principal, uint256 interest);
    event LoanDefaulted(address indexed borrower);

    modifier onlyFactory() {
        require(msg.sender == factory, "Only factory");
        _;
    }

    modifier onlyBorrower() {
        require(msg.sender == borrower, "Only borrower");
        _;
    }

    constructor(
        address _borrower,
        uint256 _principal,
        uint256 _interestRateBps,
        uint256 _durationDays,
        address _factory,
        address _creditScore
    ) {
        borrower = _borrower;
        principal = _principal;
        interestRateBps = _interestRateBps;
        durationDays = _durationDays;
        factory = _factory;
        creditScore = ICreditScore(_creditScore);
        status = Status.Requested;
    }

    function fund() external payable {
        require(status == Status.Requested, "Invalid status");
        require(msg.sender != borrower, "Borrower cannot fund own loan");
        require(msg.value > 0, "No value sent");

        uint256 remaining = principal - totalFunded;
        uint256 amountToAccept = msg.value > remaining ? remaining : msg.value;

        if (contributions[msg.sender] == 0) {
            lenders.push(msg.sender);
        }
        contributions[msg.sender] += amountToAccept;
        totalFunded += amountToAccept;

        if (totalFunded == principal) {
            status = Status.Active;
            fundedAt = block.timestamp;
            repaymentDeadline = block.timestamp + (durationDays * 1 days);
            emit LoanFunded(msg.sender, amountToAccept);
        } else {
            emit LoanPartiallyFunded(msg.sender, amountToAccept, principal - totalFunded);
        }

        // Refund excess if borrower sent more than needed to fill principal
        if (msg.value > amountToAccept) {
            uint256 excess = msg.value - amountToAccept;
            (bool refund,) = msg.sender.call{value: excess}("");
            require(refund, "Refund failed");
        }
    }

    function repay() external payable onlyBorrower {
        require(status == Status.Active, "Invalid status");

        uint256 interest = (principal * interestRateBps) / 10000;
        uint256 total = principal + interest;
        require(msg.value >= total, "Insufficient repayment");

        status = Status.Repaid;
        bool onTime = block.timestamp <= repaymentDeadline;

        creditScore.recordRepayment(borrower, principal, onTime);

        // Distribute to all lenders
        for (uint256 i = 0; i < lenders.length; i++) {
            address lender = lenders[i];
            uint256 share = contributions[lender];
            uint256 lenderInterest = (share * interestRateBps) / 10000;
            uint256 lenderTotal = share + lenderInterest;
            
            (bool sent,) = lender.call{value: lenderTotal}("");
            require(sent, "Transfer failed to lender");
        }

        uint256 excess = msg.value - total;
        if (excess > 0) {
            (bool refund,) = borrower.call{value: excess}("");
            require(refund, "Refund failed");
        }

        emit LoanRepaid(borrower, principal, interest);
    }

    uint256 public constant GRACE_PERIOD = 3 days;

    function markDefaulted() external {
        require(status == Status.Active, "Invalid status");
        
        if (msg.sender != factory) {
            require(block.timestamp > repaymentDeadline + GRACE_PERIOD, "Grace period active");
        } else {
            require(block.timestamp > repaymentDeadline, "Not yet overdue");
        }

        status = Status.Defaulted;
        creditScore.recordDefault(borrower, principal);

        uint256 balance = address(this).balance;
        if (balance > 0) {
            // Distribute remaining balance across lenders proportionally
            for (uint256 i = 0; i < lenders.length; i++) {
                address lender = lenders[i];
                uint256 share = (contributions[lender] * balance) / principal;
                if (share > 0) {
                    (bool sent,) = lender.call{value: share}("");
                    require(sent, "Transfer failed to lender");
                }
            }
        }

        emit LoanDefaulted(borrower);
    }

    function getTotalRepayment() external view returns (uint256) {
        uint256 interest = (principal * interestRateBps) / 10000;
        return principal + interest;
    }

    function getLendersCount() external view returns (uint256) {
        return lenders.length;
    }
}

contracts/LoanFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./Loan.sol";
import "./CreditScore.sol";
import "./LendingPool.sol";

/**
 * @title LoanFactory
 * @notice Creates loan instances and maintains registry
 */
contract LoanFactory {
    Loan[] public loans;
    CreditScore public creditScore;
    LendingPool public lendingPool;

    event LoanCreated(uint256 indexed loanId, address indexed borrower, uint256 principal, uint256 interestRateBps, uint256 durationDays);

    constructor() {
        creditScore = new CreditScore(address(this));
        lendingPool = new LendingPool(address(this), address(creditScore));
    }

    function createLoan(
        uint256 principal,
        uint256 durationDays
    ) external returns (uint256 loanId) {
        require(principal > 0, "Zero principal");
        require(durationDays >= 1 && durationDays <= 365, "Invalid duration");

        uint256 interestRateBps = creditScore.calculateInterestRate(msg.sender);

        Loan loan = new Loan(
            msg.sender,
            principal,
            interestRateBps,
            durationDays,
            address(this),
            address(creditScore)
        );

        loanId = loans.length;
        loans.push(loan);

        creditScore.addApprovedLoan(address(loan));
        creditScore.recordLoanRequest(msg.sender, principal);

        emit LoanCreated(loanId, msg.sender, principal, interestRateBps, durationDays);
    }

    function getLoan(uint256 loanId) external view returns (address) {
        require(loanId < loans.length, "Invalid loan");
        return address(loans[loanId]);
    }

    function getCreditScore() external view returns (address) {
        return address(creditScore);
    }

    function listLoans() external view returns (address[] memory) {
        address[] memory addrs = new address[](loans.length);
        for (uint256 i = 0; i < loans.length; i++) {
            addrs[i] = address(loans[i]);
        }
        return addrs;
    }

    function loanCount() external view returns (uint256) {
        return loans.length;
    }

    function markLoanDefaulted(uint256 loanId) external {
        require(loanId < loans.length, "Invalid loan");
        loans[loanId].markDefaulted();
    }

    /**
     * @notice Creates a loan and funds it instantly from the protocol pool
     */
    function borrowFromPool(
        uint256 principal,
        uint256 durationDays
    ) external returns (uint256 loanId) {
        // 1. Create the loan (re-using createLoan logic for consistency)
        loanId = this.createLoan(principal, durationDays);
        address loanAddr = address(loans[loanId]);

        // 2. Fund it instantly from the pool
        lendingPool.fundLoan(payable(loanAddr));
    }

    function getLendingPool() external view returns (address) {
        return address(lendingPool);
    }
}

